from flask import Flask, session, request
from functools import wraps
import redis

app = Flask(__name__)
app.secret_key = 'your_secret_key'

# Connect to Redis server
redis_client = redis.StrictRedis(host='localhost', port=6379, db=0)

def cache(expiration_time):
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            key = f.__name__ + str(args) + str(kwargs)
            cached_value = redis_client.get(key)
            if cached_value:
                return cached_value.decode('utf-8')
            result = f(*args, **kwargs)
            redis_client.setex(key, expiration_time, result)
            return result
        return decorated_function
    return decorator

@app.route('/set_session/<value>')
def set_session(value):
    session['user'] = value
    redis_client.set('session:' + request.cookies.get('session'), value)
    return f'Session set to {value}'

@app.route('/get_session')
def get_session():
    user = session.get('user', 'Not Set')
    if not user:
        user = redis_client.get('session:' + request.cookies.get('session'))
        if user:
            user = user.decode('utf-8')
    return f'Current Session: {user}'

@app.route('/expensive_query/<param>')
@cache(expiration_time=300)  # Cache for 5 minutes
def expensive_query(param):
    # Simulate an expensive database query
    result = f"Expensive Query Result for {param}"
    return result

